// src/components/Sidebar.js
import { Home, Calendar, BookOpen, Users, Mail, Settings, HelpCircle } from 'lucide-react';

export default function Sidebar({ onMenuClick, active }) {
  return (
    <aside className="min-h-screen w-64 bg-white border-r flex flex-col justify-between">
      <div>
        {/* Logo e nome */}
        <div className="flex items-center gap-2 p-6">
          <span className="bg-gray-200 rounded-full p-2">
            <span className="font-bold text-xl">*</span>
          </span>
          <span className="font-bold text-lg">PoliUb Atendimento</span>
        </div>

        {/* Menu principal */}
        <nav className="flex flex-col gap-2 mt-4">
          <SidebarItem
            icon={<Home size={20} />}
            label="Dashboard"
            active={active === 'dashboard'}
            onClick={() => onMenuClick('dashboard')}
          />
          <SidebarItem
            icon={<Calendar size={20} />}
            label="Agendar Paciente"
            active={active === 'agendar'}
            onClick={() => onMenuClick('agendar')}
          />
          <SidebarItem
            icon={<BookOpen size={20} />}
            label="Disciplinas"
            active={active === 'disciplinas'}
            onClick={() => onMenuClick('disciplinas')}
          />
          <SidebarItem
            icon={<Users size={20} />}
            label="Pacientes"
            active={active === 'pacientes'}
            onClick={() => onMenuClick('pacientes')}
          />
          <SidebarItem
            icon={<Users size={20} />}
            label="Alunos"
            active={active === 'alunos'}
            onClick={() => onMenuClick('alunos')}
          />
          <SidebarItem
            icon={<Mail size={20} />}
            label="Solicitações"
            active={active === 'solicitacoes'}
            onClick={() => onMenuClick('solicitacoes')}
          />
        </nav>
      </div>

      {/* Configurações e ajuda */}
      <div className="flex flex-col gap-2 p-6 pb-4">
        <SidebarItem
          icon={<Settings size={20} />}
          label="Configurações"
          onClick={() => onMenuClick('configuracoes')}
        />
        <SidebarItem
          icon={<HelpCircle size={20} />}
          label="Ajuda"
          onClick={() => onMenuClick('ajuda')}
        />
      </div>
    </aside>
  );
}

// Item de menu reutilizável
function SidebarItem({ icon, label, active, onClick }) {
  return (
    <button
      className={`
        flex items-center gap-3 p-3 rounded-xl transition
        ${active ? 'bg-gray-200 font-bold text-black' : 'hover:bg-gray-100 text-gray-700'}
      `}
      onClick={onClick}
    >
      {icon}
      {label}
    </button>
  );
}
